(()=>{"use strict";!function(){const t=document.querySelectorAll('.toggle input[type="checkbox"], .toggle input[type="radio"]');t&&t.forEach((t=>{const e=t.parentElement,o=navigator.userAgent;(/iPad|iPhone|iPod/.test(o)||"MacIntel"===navigator.platform&&navigator.maxTouchPoints>1)&&e.setAttribute("tabindex","-1"),t.addEventListener("click",(()=>{e.classList.remove("toggle--ripple"),e.classList.add("toggle--ripple")}))}))}()})();